        value_file_.close();
        std::ofstream unexport("/sys/class/gpio/unexport");
        unexport << pin_;
        std::cout << "GPIO " << pin_ << " released" << std::endl;
    }

    void write(bool high) {
        value_file_ << (high ? "1" : "0") << std::flush;
    }

