**2. CRTP 零开销控制器**

```cpp
template<typename Derived, typename StateType, typename ActionType>
class ControllerBase {
public:
    ActionType compute(const StateType& state, const StateType& target) {
        return static_cast<Derived*>(this)->compute_impl(state, target);
    }
};

class PDController : public ControllerBase<PDController, double, double> {
    friend class ControllerBase<PDController, double, double>;
public:
    PDController(double kp, double kd) : kp_(kp), kd_(kd), prev_error_(0) {}
private:
    double compute_impl(const double& state, const double& target) {
        double error = target - state;
        double d_error = error - prev_error_;
        prev_error_ = error;
        return kp_ * error + kd_ * d_error;
    }
    double kp_, kd_, prev_error_;
};

// PDController pd(10.0, 1.0);
// double torque = pd.compute(current_angle, target_angle);
// 编译后和直接调用 compute_impl 完全等价, 零开销
```

